module add1 (
    input wire a,
    input wire b,
    input wire Cin,
    output wire y,
    output wire Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [7:0] ext_mul_a;
    wire [7:0] ext_mul_b;
    assign ext_mul_a = {{4{1'b0}}, mul_a};
    assign ext_mul_b = {{4{1'b0}}, mul_b};

    genvar i;
    wire [7:0] pp [3:0];
    generate
        for(i = 0; i < 4; i=i+1) begin
            assign pp[i] = (ext_mul_b[i])? ext_mul_a << i : 'd0;
        end
    endgenerate

    reg [7:0] sum_tmp1;
    reg [7:0] sum_tmp2;
    reg [7:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_tmp1 <= 8'd0;
            sum_tmp2 <= 8'd0;
        end
        else begin
            sum_tmp1 <= pp[0] + pp[1];
            sum_tmp2 <= pp[2] + pp[3];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out_reg <= 8'd0;
        end
        else begin
            mul_out_reg <= sum_tmp1 + sum_tmp2;
        end
    end

    assign mul_out = mul_out_reg;
endmodule

module verified_multi_pipe#(
	parameter size = 4
)(
	input 						clk 		,   
	input 						rst_n		,
	input	[size-1:0]			mul_a		,
	input	[size-1:0]			mul_b		,

 	output	reg	[size*2-1:0]	mul_out		
);

parameter N = 2 * size;

reg     [N-1:0]     sum_tmp1                ;
reg     [N-1:0]     sum_tmp2                ;
wire    [N-1:0]     mul_a_extend            ;
wire    [N-1:0]     mul_b_extend            ;

wire    [N-1:0]     mul_result[size-1:0]    ;

genvar i;
generate
    for(i = 0; i < size; i = i + 1) begin:add
        assign mul_result[i] = mul_b[i] ? mul_a_extend << i : 'd0;
    end
endgenerate

assign mul_a_extend = {{size{1'b0}}, mul_a};
assign mul_b_extend = {{size{1'b0}}, mul_b};

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end
    else begin
        sum_tmp1 <= mul_result[0] + mul_result[1];
        sum_tmp2 <= mul_result[2] + mul_result[3];
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [1:0] cnt;
reg [3:0] data;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 2'b00;
    end else begin
        if (cnt == 2'b11) begin
            cnt <= 2'b00;
            data <= d;
            valid <= 1'b1;
        end else begin
            cnt <= cnt + 1'b1;
            data <= {data[2:0], data[3]};
            valid <= 1'b0;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

module adder_bcd (
    input  [3:0] A,
    input  [3:0] B,
    input  Cin,
    output [3:0] Sum,
    output Cout
);

wire [4:0] temp_sum;
wire [4:0] corrected_sum;
wire correction_needed;

assign temp_sum = A + B + Cin;

assign correction_needed = (temp_sum > 9);

assign corrected_sum = correction_needed ? (temp_sum + 6) : temp_sum;

assign Sum = corrected_sum[3:0];
assign Cout = corrected_sum[4];
endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

reg [15:0] a_reg;
reg [7:0] b_reg;

always @(*) begin
    a_reg = A;
    b_reg = B;
end

always @(*) begin
    if (b_reg == 0) begin
        result = 0;
        odd = a_reg;
    end else begin
        result = a_reg / b_reg;
        odd = a_reg % b_reg;
    end
end
endmodule

