module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end
    else begin
        case (state)
            idle: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b0;
                cnt <= 8'd0;
                state <= s1_red;
            end
            s1_red: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s2_yellow: begin
                red <= 1'b0;
                yellow <= 1'b1;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s3_green;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s3_green: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
        endcase
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 1'b0;
        p_yellow <= 1'b0;
        p_green <= 1'b0;
    end
    else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule

