module comparator_4bit (
    input [3:0] A,
    input [3:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);

    wire [3:0] diff;
    wire carry;

    assign {carry, diff} = A - B;

    always @(*) begin
        if (carry) begin
            A_greater = 1'b0;
            A_equal = 1'b0;
            A_less = 1'b1;
        end
        else if (diff == 4'b0000) begin
            A_greater = 1'b0;
            A_equal = 1'b1;
            A_less = 1'b0;
        end
        else begin
            A_greater = 1'b1;
            A_equal = 1'b0;
            A_less = 1'b0;
        end
    end

endmodule

