                        state <= s0;
                    end
                    data_out <= 1'b0;
                end
                s3: begin
                    if (~data_in) begin
                        state <= s0;
                    end else begin
                        state <= s3;
                    end
                    data_out <= 1'b1;
                end
                default: begin
                    state <= s0;
                    data_out <= 1'b0;
