assign wfull = (wgray == ~rgray);

reg [ADDR_WIDTH:0] rgray, rbin;
wire [ADDR_WIDTH:0] rgraynext, rbinnext;

assign rgraynext = rbinnext >> 1;
assign rbinnext = rbin + { {(ADDR_WIDTH){1'b0}}, rinc };

