	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule

module clkgenerator #(
    parameter PERIOD = 10
) (
    output reg clk
);

    initial begin
        clk = 0;
    end

    always @(clk) begin
        #(PERIOD/2) clk = ~clk;
    end
endmodule

module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

reg [3:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 4'b0000;
    end else if (din_valid) begin
        if (cnt == 4'b1000) begin
            cnt <= 4'b0000;
        end else begin
            cnt <= cnt + 1;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_parallel <= 8'b0;
    end else if (din_valid) begin
        case (cnt)
            4'b0000: dout_parallel[7] <= din_serial;
            4'b0001: dout_parallel[6] <= din_serial;
            4'b0010: dout_parallel[5] <= din_serial;
            4'b0011: dout_parallel[4] <= din_serial;
            4'b0100: dout_parallel[3] <= din_serial;
            4'b0101: dout_parallel[2] <= din_serial;
            4'b0110: dout_parallel[1] <= din_serial;
            4'b0111: dout_parallel[0] <= din_serial;
            default: dout_parallel <= dout_parallel;
        endcase
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_valid <= 1'b0;
    end else if (din_valid && (cnt == 4'b1000)) begin
        dout_valid <= 1'b1;
    end else begin
        dout_valid <= 1'b0;
    end
end

endmodule

module sequence_detector #(
    parameter IDLE = 5'b00001,
    parameter S1   = 5'b00010,
    parameter S2   = 5'b00100,
    parameter S3   = 5'b01000,
    parameter S4   = 5'b10000
) (
    input  clk,
    input  rst_n,
    input  data_in,
    output reg sequence_detected
);

    reg [4:0] state, next_state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    always @(*) begin
        next_state = state;
        sequence_detected = 1'b0;

        case (state)
            IDLE: begin
                if (data_in) begin
                    next_state = S1;
                end else begin
                    next_state = IDLE;
                end
            end
            S1: begin
                if (!data_in) begin
                    next_state = S2;
                end else begin
                    next_state = IDLE;
                end
            end
            S2: begin
                if (!data_in) begin
                    next_state = S3;
                end else begin
                    next_state = IDLE;
                end
            end
            S3: begin
                if (data_in) begin
                    next_state = S4;
                end else begin
                    next_state = IDLE;
                end
            end
            S4: begin
                next_state = IDLE;
                sequence_detected = 1'b1;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

endmodule

module LIFObuffer (
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

reg [3:0] stack_mem [0:3];
integer SP = 4;

always @(posedge Clk or posedge Rst) begin
    if (Rst) begin
        SP <= 4;
    end else if (EN) begin
        if (~FULL && ~RW) begin
            stack_mem[SP] <= dataIn;
            SP <= SP - 1;
        end else if (~EMPTY && RW) begin
            SP <= SP + 1;
        end
    end
end

always @(SP) begin
    EMPTY = (SP == 4);
    FULL = (SP == 0);
end

always @(posedge Clk or posedge Rst) begin
    if (Rst) begin
        dataOut <= 4'b0000;
    end else if (EN && RW && ~EMPTY) begin
        dataOut <= stack_mem[SP];
    end else begin
        dataOut <= 4'b0000;
    end
end

endmodule

module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk) begin
    if (rst) begin
        counter <= 0;
        a_mantissa <= 0;
        b_mantissa <= 0;
        z_mantissa <= 0;
        a_exponent <= 0;
        b_exponent <= 0;
        z_exponent <= 0;
        a_sign <= 0;
        b_sign <= 0;
        z_sign <= 0;
        product <= 0;
        guard_bit <= 0;
        round_bit <= 0;
        sticky <= 0;
        z <= 0;
    end else begin
        case (counter)
            0: begin
                a_mantissa <= {1'b1, a[22:0]};
                b_mantissa <= {1'b1, b[22:0]};
                a_exponent <= a[30:23] - 127;
                b_exponent <= b[30:23] - 127;
                a_sign <= a[31];
                b_sign <= b[31];
                counter <= 1;
            end
            1: begin
                if ((a_exponent == 128 && a_mantissa != 0) || (b_exponent == 128 && b_mantissa != 0)) begin
                    z <= 255;
                    counter <= 2;
                end else begin
                    if (a_exponent == 0 || b_exponent == 0) begin
                        z <= 0;
                        counter <= 2;
                    end else begin
                        z_sign <= a_sign ^ b_sign;
                        product <= a_mantissa * b_mantissa;
                        counter <= 2;
                    end
                end
            end
            2: begin
                if (product[49]) begin
                    z_mantissa <= product[48:25];
                    z_exponent <= a_exponent + b_exponent;
                end else begin
                    z_mantissa <= product[47:24];
                    z_exponent <= a_exponent + b_exponent - 1;
                end
                counter <= 3;
            end
            3: begin
                guard_bit <= product[24];
                round_bit <= product[23];
                sticky <= |product[22:0];
                counter <= 4;
            end
            4: begin
                if (guard_bit && (round_bit || sticky)) begin
                    z_mantissa <= z_mantissa + 1;
                    if (z_mantissa == 256) begin
                        z_exponent <= z_exponent + 1;
                        if (z_exponent == 255) begin
                            z <= 255;
                        end
                    end
                end
                counter <= 5;
            end
            5: begin
                if (z_exponent == 0) begin
                    z <= 0;
                end else begin
                    z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                end
                counter <= 0;
            end
        endcase
    end
end

endmodule

module radix2_div (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

reg [7:0] dividend_reg, divisor_reg;
reg [15:0] SR;
reg [3:0] cnt;
reg start_cnt;
reg [7:0] NEG_DIVISOR;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        dividend_reg <= 0;
        divisor_reg <= 0;
        SR <= 0;
        cnt <= 0;
        start_cnt <= 0;
        NEG_DIVISOR <= 0;
        res_valid <= 0;
        result <= 0;
    end else if (opn_valid && !res_valid) begin
        dividend_reg <= dividend;
        divisor_reg <= divisor;
        SR <= {dividend_reg, 1'b0};
        NEG_DIVISOR <= sign ? -divisor_reg : ~divisor_reg + 1'b1;
        cnt <= 4'b1000;
        start_cnt <= 1'b1;
        res_valid <= 1'b0;
    end else if (start_cnt) begin
        if (cnt[3]) begin
            start_cnt <= 1'b0;
            res_valid <= 1'b1;
            result <= SR[15:0];
        end else begin
            cnt <= cnt - 1'b1;
            {SR[14:0], SR[15]} <= (SR[15:8] >= NEG_DIVISOR) ? {SR[14:0], 1'b1} : {SR[14:0], 1'b0};
        end
    end else if (res_valid && res_ready) begin
        res_valid <= 1'b0;
    end
end

endmodule
